// Solution
#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
  vector<int> fib(int n) {
    vector<int> result; result.push_back(0); result.push_back(1);
    for (int i = 2; i <= n; i++) {
      result.push_back(result[i-2] + result[i-1]);
    }
    return result;
  }
};

int main() {
  Solution solution;
  int n;
  cin >> n;
  vector<int> result = solution.fib(n);
  for (int i = 0; i < n; i++) {
    cout << result[i] << ' ';
  }
  cout << endl;
  return 0;
}

