// Solution
import java.util.*;

public class Solution {
  public List<Integer> fib(int n) {
    List<Integer> result = new ArrayList<>(); result.add(0); result.add(1);
    for (int i = 2; i <= n; i++) {
      result.add(result.get(i-2) + result.get(i-1));
    }
    return result;
  }

  public static void main(String[] args) {
    Solution solution = new Solution();
    int n;
    Scanner scanner = new Scanner(System.in);
    scanner.nextInt();
    List<Integer> result = solution.fib(n);
    for (int i = 0; i < n; i++) {
      System.out.print(result.get(i) + ' ');
    }
    System.out.println();
  }
}

