// Solution
from typing import List
import sys

class Solution:
  def fib(self, n: int) -> List[int]:
    result = [0, 1]
    for i in range(2, n):
      result.append(result[i-2] + result[i-1])
    return result

def main():
  solution = Solution()
  n = int(input())
  result = solution.fib(n)
  print(' '.join(map(str, result)))

if __name__ == '__main__':
  main()

